const res = $input.first().json;
const status = res.status;
if (status !== 'OK' || !res.results || !res.results.length) {
  throw new Error('Could not geocode address: ' + (res.error_message || status));
}

const result = res.results[0];
const lat = result.geometry.location.lat;
const lng = result.geometry.location.lng;
const formatted_address = result.formatted_address;

// Apex Roofing base (6806 S 25 E, Pendleton, IN 46064) — geocoded once, hardcoded to avoid a 2nd Maps API call per quote
const BASE_LAT = 40.0007237;
const BASE_LNG = -85.6672223;
const ROUTE_FACTOR = 1.3; // straight-line -> approximate road-distance fudge factor

function haversineMiles(lat1, lon1, lat2, lon2) {
  const R = 3958.8;
  const toRad = d => d * Math.PI / 180;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat / 2) ** 2 + Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon / 2) ** 2;
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

const straightLineMiles = haversineMiles(BASE_LAT, BASE_LNG, lat, lng);
const miles = Math.round(straightLineMiles * ROUTE_FACTOR * 10) / 10;

// Travel zones — must match [Quote] Roofing Bot v1.0.0 pricing sheet "travel" section
let travel_zone_label, travel_fee;
if (miles <= 10) { travel_zone_label = 'Local (within 10 miles)'; travel_fee = 0; }
else if (miles <= 25) { travel_zone_label = 'Zone 1 (11-25 miles)'; travel_fee = 75; }
else if (miles <= 45) { travel_zone_label = 'Zone 2 (26-45 miles)'; travel_fee = 175; }
else if (miles <= 70) { travel_zone_label = 'Zone 3 (46-70 miles)'; travel_fee = 350; }
else { travel_zone_label = 'Out of Service Area (over 70 miles)'; travel_fee = -1; }

// Ground scale at this location for a zoom-20 static map (Web Mercator projection)
const ZOOM = 20;
const metersPerPixel = 156543.03392 * Math.cos(lat * Math.PI / 180) / Math.pow(2, ZOOM);
const feetPerPixel = Math.round(metersPerPixel * 3.28084 * 1000) / 1000;

return [{ json: {
  lat, lng, formatted_address,
  miles, travel_zone_label, travel_fee,
  feet_per_pixel: feetPerPixel
} }];

const item = $input.first();
const binaryKeys = Object.keys(item.binary || {});
if (binaryKeys.length === 0) {
  throw new Error('Failed to fetch satellite image — no binary data returned.');
}
const binaryPropertyName = binaryKeys[0];
const buffer = await this.helpers.getBinaryDataBuffer(0, binaryPropertyName);
const base64Data = buffer.toString('base64');
const mimeType = item.binary[binaryPropertyName].mimeType || 'image/png';

const geo = $('Extract Geo & Travel').first().json;
const feetPerPixel = geo.feet_per_pixel;
const imageWidthFeet = Math.round(feetPerPixel * 600);

const prompt = `You are a professional roofing estimator analyzing a top-down satellite image of a residential property to build a preliminary roof quote.

TARGET PROPERTY: The image is centered exactly on the target address. If multiple buildings/roofs are visible, always analyze the building whose center is closest to the center of the image — that is the target property. Ignore neighboring houses, garages, and outbuildings unless they are clearly part of the same roof structure.

SCALE REFERENCE: This image is 600x600 pixels, captured directly overhead at zoom level 20. At this location, each pixel represents approximately ${feetPerPixel} feet on the ground (the image covers roughly a ${imageWidthFeet}ft x ${imageWidthFeet}ft area). Use this scale to measure the roof's pixel dimensions and convert to square feet.

IMPORTANT LIMITATION: This is a straight-down satellite view, not an oblique aerial photo, so true roof pitch (slope) cannot be measured directly. Estimate pitch category using indirect visual cues — shadow patterns and darkness gradients across roof faces, and roofline style (multiple dramatic gables/dormers tend to be steeper; simple low-profile rooflines tend to be shallower). Most US Midwest residential roofs are 5:12–7:12 — default to "medium" when uncertain.

RESPONSE FORMAT: Respond with ONLY a single raw JSON object — no reasoning, no explanation, no markdown code fences, no text before or after. Your entire response must start with { and end with }. Do any analysis silently and output just the final JSON.

{"footprint_sqft": 0, "pitch_estimate": "medium", "facet_count": 0, "skylights": 0, "chimneys": 0, "dormers": 0, "notes": ""}

Field definitions:
- footprint_sqft: target building's roof footprint area in square feet, measured from pixel dimensions using the scale above
- pitch_estimate: one of "low", "medium", "steep", "very_steep"
- facet_count: count of distinct visible roof planes/facets on the target building
- skylights / chimneys / dormers: counts of each visible on the target building's roof
- notes: brief notes — roof condition visible from above, tree coverage obscuring the view, confidence level, or anything unusual`;

return [{ json: {
  image_data: base64Data,
  image_media_type: mimeType,
  prompt
} }];

const response = $input.first().json;
const rawText = response.content?.[0]?.text ?? '';

let parsed;
try {
  const clean = rawText.replace(/```json\s*/gi, '').replace(/```/g, '').trim();
  const match = clean.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('no JSON object found');
  parsed = JSON.parse(match[0]);
} catch (e) {
  throw new Error('Vision API returned non-JSON: ' + rawText.substring(0, 300));
}

return [{ json: parsed }];

const vision = $input.first().json;
const geo = $('Extract Geo & Travel').first().json;

// Pitch estimate -> ratio -> area multiplier (sqrt(1+(rise/run)^2)) — must match [Quote] Roofing Bot v1.0.0 pricing sheet "pitch" section
const PITCH_MAP = {
  low:        { ratio: '4_12',  multiplier: 1.054 },
  medium:     { ratio: '6_12',  multiplier: 1.118 },
  steep:      { ratio: '9_12',  multiplier: 1.250 },
  very_steep: { ratio: '11_12', multiplier: 1.357 }
};
const pitch = PITCH_MAP[vision.pitch_estimate] || PITCH_MAP.medium;

const STEEP_THRESHOLD_12THS = 7;
const VERY_STEEP_THRESHOLD_12THS = 10;
const pitchNumerator = parseInt(pitch.ratio.split('_')[0], 10);
let steep_surcharge_tier = 'none';
if (pitchNumerator >= VERY_STEEP_THRESHOLD_12THS) steep_surcharge_tier = 'very_steep';
else if (pitchNumerator >= STEEP_THRESHOLD_12THS) steep_surcharge_tier = 'steep';

const footprintSqft = Math.max(0, Number(vision.footprint_sqft) || 0);
const totalRoofSqft = Math.round(footprintSqft * pitch.multiplier);

const facetCount = Math.max(1, Number(vision.facet_count) || 1);
let complexity, wastePct;
if (facetCount <= 4) { complexity = 'simple'; wastePct = 0.10; }
else if (facetCount <= 8) { complexity = 'moderate'; wastePct = 0.15; }
else { complexity = 'complex'; wastePct = 0.20; }

const materialSquaresNeeded = Math.ceil((totalRoofSqft * (1 + wastePct)) / 100);
const tearOffSquares = Math.ceil(totalRoofSqft / 100);

return [{ json: {
  formatted_address: geo.formatted_address,
  miles: geo.miles,
  travel_zone_label: geo.travel_zone_label,
  travel_fee: geo.travel_fee,
  footprint_sqft: footprintSqft,
  pitch_estimate: vision.pitch_estimate || 'medium',
  pitch_ratio: pitch.ratio,
  pitch_multiplier: pitch.multiplier,
  total_roof_sqft: totalRoofSqft,
  facet_count: facetCount,
  complexity,
  waste_pct: wastePct,
  material_squares_needed: materialSquaresNeeded,
  tear_off_squares: tearOffSquares,
  steep_surcharge_tier,
  skylights: Math.max(0, Number(vision.skylights) || 0),
  chimneys: Math.max(0, Number(vision.chimneys) || 0),
  dormers: Math.max(0, Number(vision.dormers) || 0),
  notes: vision.notes || ''
} }];
